public int maxCandies(int[] candies, int k) {
    int left = 1;
    int right = 0;

    for (int candy : candies) {
        right = Math.max(right, candy);
    }

    while (left <= right) {
        int mid = left + (right - left) / 2;
        int count = 0;
        for (int candy : candies) {
            count += candy / mid;
        }
        if (count >= k) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    return right;
}
